  type: string;
  pattern: string;
  weeks_seen: number;
  total: number;
  avg_confidence: number;
  est_hours_per_month: number;
  automation_potential: 'high' | 'medium';
}

export interface EscalationBottleneck {
  person: string;
  escalations: number;
  interpretation: string;
}

export interface MeetingOverload {
  person: string;
  date: string;
  meetings: number;
  interpretation: string;
